struct hl_cache_entry {
	char *ln;
	int gen;
	int blockhl;
	int blockatt;
	int ftidx;
};
#define HL_CACHE_BITS	10
#define HL_CACHE_SIZE	(1 << HL_CACHE_BITS)
#define HL_CACHE_MASK	(HL_CACHE_SIZE - 1)
#define HL_CACHE_PROBE	8
static struct hl_cache_entry hl_cache[HL_CACHE_SIZE];
static int hl_cache_gen = 1;
static struct lbuf *syn_lb;
static int syn_row;

static int hl_cache_hash(char *ln)
{
	return (int)(((size_t)ln >> 4) & HL_CACHE_MASK);
}

static struct hl_cache_entry *hl_cache_find(char *ln)
{
	if (!ln)
		return NULL;
	int h = hl_cache_hash(ln);
	for (int i = 0; i < HL_CACHE_PROBE; i++) {
		struct hl_cache_entry *e = &hl_cache[(h + i) & HL_CACHE_MASK];
		if (e->ln == ln && e->gen == hl_cache_gen)
			return e;
		if (!e->ln)
			return NULL;
	}
	return NULL;
}

static void hl_cache_set(char *ln, int blockhl, int blockatt_v, int fti)
{
	if (!ln)
		return;
	int h = hl_cache_hash(ln);
	struct hl_cache_entry *slot = &hl_cache[h];
	for (int i = 0; i < HL_CACHE_PROBE; i++) {
		struct hl_cache_entry *e = &hl_cache[(h + i) & HL_CACHE_MASK];
		if (!e->ln || e->ln == ln || e->gen != hl_cache_gen) {
			slot = e;
			break;
		}
	}
	slot->ln = ln;
	slot->gen = hl_cache_gen;
	slot->blockhl = blockhl;
	slot->blockatt = blockatt_v;
	slot->ftidx = fti;
}

void syn_blockhl_invalidate(void)
{
	hl_cache_gen++;
}

void syn_setrow(struct lbuf *lb, int row)
{
	syn_lb = lb;
	syn_row = row;
}

static int *hl_scan_att;
static int hl_scan_att_sz;
static int hl_scan_active;

/* extend the cache chain backward to row 0 or nearest cached row */
static void hl_scan_until(int target_row)
{
	if (hl_scan_active || target_row <= 0)
		return;
	int from = 0;
	for (int r = target_row - 1; r > 0; r--) {
		char *ln = lbuf_get(syn_lb, r);
		struct hl_cache_entry *e = hl_cache_find(ln);
		if (e && e->ftidx == ftidx) {
			from = r + 1;
			break;
		}
	}
	int saved_row = syn_row;
	int saved_blockhl = syn_blockhl;
	int saved_blockatt = blockatt;
	int saved_last_scdir = last_scdir;
	last_scdir = 0;
	hl_scan_active = 1;
	for (int r = from; r <= target_row; r++) {
		char *ln = lbuf_get(syn_lb, r);
		if (!ln)
			break;
		int len = lbuf_s(ln)->len;
		if (len + 1 > hl_scan_att_sz) {
			hl_scan_att_sz = (len + 1) * 2;
			hl_scan_att = erealloc(hl_scan_att, hl_scan_att_sz * sizeof(int));
		}
		memset(hl_scan_att, 0, (len + 1) * sizeof(int));
		syn_row = r;
		syn_highlight(hl_scan_att, ln, len);
	}
	hl_scan_active = 0;
	syn_row = saved_row;
	syn_blockhl = saved_blockhl;
	blockatt = saved_blockatt;
	last_scdir = saved_last_scdir;
}

